def rel_score(km, surname_jaccard):
    geo = 1.0 if km <= 2 else 0.0
    return round(0.5 * geo + 0.5 * surname_jaccard, 1)
print(rel_score(1.2, 1.0), rel_score(5.0, 0.4))

