txs = [("A","D",1), ("C","D",1), ("A","E",1), ("C","F",1)]
def neighbors(txs, node):
    s = set()
    for x, y, _ in txs:
        if x == node:
            s.add(y)
        if y == node:
            s.add(x)
    return s
print(sorted(neighbors(txs, "A") & neighbors(txs, "C")))

# dual skeptic-H1 · S13-T3-A-E2
def uncertainty_band(missing, conflict):
    if conflict or len(missing) >= 2:
        return "high"
    if missing:
        return "med"
    return "low"
print(uncertainty_band([], False), uncertainty_band(["e"], False),
      uncertainty_band(["e","p"], False), uncertainty_band([], True))

# dual skeptic-H1 · S13-T3-B-E2
from math import isfinite
th = {"accept_min": 0.8, "review_low": 0.4}
def decide_ops_status(score, unc, th):
    if isinstance(score, bool) or not isinstance(score, (int, float)):
        return "invalid_input"
    if not isfinite(score) or not 0.0 <= score <= 1.0 or unc not in {"low", "med", "high"}:
        return "invalid_input"
    if unc == "high":
        return "needs_review"
    if score < th["review_low"]:
        return "abstain"
    if score < th["accept_min"]:
        return "needs_review"
    return "accept_pair"
for s, u in [(-0.1, "low"), (0.399, "low"), (0.4, "low"), (0.799, "low"), (0.8, "low"), (1.0, "low"), (0.9, "high")]:
    print(s, u, decide_ops_status(s, u, th))

